function ida_num($v,$d=2){return number_format((float)$v,$d,',','.');}
function ida_dt($v){$v=trim((string)$v);if($v==='')return '';$v=str_replace('T',' ',$v);if(preg_match('/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}$/',$v))$v.=':00';$dt=DateTime::createFromFormat('Y-m-d H:i:s',$v);return ($dt&&$dt->format('Y-m-d H:i:s')===$v)?$v:'';}
function ida_next_no($date){global $db;$prefix='DT'.date('Ym',strtotime($date));$r=$db->fetch("SELECT downtime_no FROM erp_production_downtime WHERE downtime_no LIKE ? ORDER BY downtime_no DESC LIMIT 1",array($prefix.'%'));$n=1;if($r&&preg_match('/(\d{5})$/',$r->downtime_no,$m))$n=(int)$m[1]+1;return $prefix.sprintf('%05d',$n);}
