    $productionId=isset($_POST['production_id'])?(int)$_POST['production_id']:0;$operationId=isset($_POST['operation_id'])?(int)$_POST['operation_id']:0;$start=ida_dt(isset($_POST['start_time'])?$_POST['start_time']:'');$end=ida_dt(isset($_POST['end_time'])?$_POST['end_time']:'');$reason=isset($_POST['reason_text'])?trim($_POST['reason_text']):'';
