    erpkb_excel_apply_standard_style($excel,array('sheet'=>$sh,'title'=>erp_export_title('INPUT DOWNTIME REPORT'),'header_row'=>4,'first_data_row'=>5,'last_data_row'=>max(5,$r-1),'column_count'=>17,'decimal_columns'=>array('K'),'filters'=>array('Downtime Date'=>$from.' s/d '.$to,'Plant'=>isset($_GET['plant'])?$_GET['plant']:erp_export_all_text(),'Category'=>isset($_GET['category'])?$_GET['category']:erp_export_all_text())));$tmp=erpkb_excel_temp_file('input_downtime_');PHPExcel_IOFactory::createWriter($excel,'Excel2007')->save($tmp);$size=@filesize($tmp);$sig=@file_get_contents($tmp,false,null,0,2);if(!$size||$sig!=='PK'){@unlink($tmp);while(ob_get_level()>$initial)ob_end_clean();header('Content-Type:text/plain; charset=utf-8');echo erp_t('export_excel_invalid_file','File Excel gagal dibuat dengan benar.');exit;}while(ob_get_level()>$initial)ob_end_clean();header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');header('Content-Disposition: attachment; filename="input_downtime_'.date('Ymd_His').'.xlsx"');header('Content-Length: '.$size);header('Cache-Control: max-age=0');header('Pragma: public');readfile($tmp);@unlink($tmp);exit;
